import numpy as np
from scipy.stats import norm

def black_scholes_price(S, K, T, r, sigma, option_type='call'):
    """Standard BS price."""
    if T <= 0:
        if option_type == 'call':
            return max(S - K, 0)
        else:
            return max(K - S, 0)
    d1 = (np.log(S/K) + (r + sigma**2/2)*T) / (sigma*np.sqrt(T))
    d2 = d1 - sigma*np.sqrt(T)
    if option_type == 'call':
        return S * norm.cdf(d1) - K * np.exp(-r*T) * norm.cdf(d2)
    else:
        return K * np.exp(-r*T) * norm.cdf(-d2) - S * norm.cdf(-d1)

class NumericalGreeks:
    """
    Calculate Greeks using finite differences.
    """

    def __init__(self, S, K, T, r, sigma, option_type='call'):
        self.S = S
        self.K = K
        self.T = T
        self.r = r
        self.sigma = sigma
        self.option_type = option_type

    def price(self):
        return black_scholes_price(self.S, self.K, self.T, self.r, 
                                   self.sigma, self.option_type)

    def delta_numerical(self, h=0.01):
        """
        Calculate delta using central difference.
        """
        V_up = black_scholes_price(self.S + h, self.K, self.T, self.r, 
                                   self.sigma, self.option_type)
        V_down = black_scholes_price(self.S - h, self.K, self.T, self.r, 
                                     self.sigma, self.option_type)
        return (V_up - V_down) / (2 * h)

    def gamma_numerical(self, h=0.01):
        """
        Calculate gamma using central difference.
        """
        V = self.price()
        V_up = black_scholes_price(self.S + h, self.K, self.T, self.r, 
                                   self.sigma, self.option_type)
        V_down = black_scholes_price(self.S - h, self.K, self.T, self.r, 
                                     self.sigma, self.option_type)
        return (V_up - 2*V + V_down) / (h**2)

    def vega_numerical(self, h=0.001):
        """
        Calculate vega using central difference (per 1% change).
        """
        V_up = black_scholes_price(self.S, self.K, self.T, self.r, 
                                   self.sigma + h, self.option_type)
        V_down = black_scholes_price(self.S, self.K, self.T, self.r, 
                                     self.sigma - h, self.option_type)
        # Scale to per 1% (0.01) change in vol
        return (V_up - V_down) / (2 * h) * 0.01

    def theta_numerical(self, h=1/365):
        """
        Calculate theta using forward difference (daily).
        """
        V = self.price()
        if self.T - h > 0:
            V_later = black_scholes_price(self.S, self.K, self.T - h, self.r, 
                                          self.sigma, self.option_type)
        else:
            V_later = max(self.S - self.K, 0) if self.option_type == 'call' else max(self.K - self.S, 0)
        return (V_later - V) / h

    def delta_analytical(self):
        d1 = (np.log(self.S/self.K) + (self.r + self.sigma**2/2)*self.T) / (self.sigma*np.sqrt(self.T))
        if self.option_type == 'call':
            return norm.cdf(d1)
        else:
            return norm.cdf(d1) - 1

    def gamma_analytical(self):
        d1 = (np.log(self.S/self.K) + (self.r + self.sigma**2/2)*self.T) / (self.sigma*np.sqrt(self.T))
        return norm.pdf(d1) / (self.S * self.sigma * np.sqrt(self.T))

    def vega_analytical(self):
        d1 = (np.log(self.S/self.K) + (self.r + self.sigma**2/2)*self.T) / (self.sigma*np.sqrt(self.T))
        return self.S * norm.pdf(d1) * np.sqrt(self.T) / 100

    def theta_analytical(self):
        d1 = (np.log(self.S/self.K) + (self.r + self.sigma**2/2)*self.T) / (self.sigma*np.sqrt(self.T))
        d2 = d1 - self.sigma*np.sqrt(self.T)
        term1 = -(self.S * norm.pdf(d1) * self.sigma) / (2 * np.sqrt(self.T))
        if self.option_type == 'call':
            term2 = -self.r * self.K * np.exp(-self.r*self.T) * norm.cdf(d2)
        else:
            term2 = self.r * self.K * np.exp(-self.r*self.T) * norm.cdf(-d2)
        return (term1 + term2) / 365

    def compare_to_analytical(self):
        """
        Compare numerical to analytical Greeks.
        """
        results = {}

        for greek in ['delta', 'gamma', 'vega', 'theta']:
            numerical = getattr(self, f'{greek}_numerical')()
            analytical = getattr(self, f'{greek}_analytical')()
            results[greek] = {
                'numerical': numerical,
                'analytical': analytical,
                'error': abs(numerical - analytical)
            }

        return results

# Test and compare
params = {'S': 100, 'K': 100, 'T': 0.5, 'r': 0.05, 'sigma': 0.20}
numerical = NumericalGreeks(**params)

print("Numerical vs Analytical Greeks:")
print("="*50)
comparison = numerical.compare_to_analytical()
print(f"{'Greek':>10} {'Numerical':>12} {'Analytical':>12} {'Error':>12}")
print("-"*50)
for greek, values in comparison.items():
    print(f"{greek:>10} {values['numerical']:>12.6f} {values['analytical']:>12.6f} "
          f"{values['error']:>12.6f}")

print("\nConvergence Analysis for Delta:")
for h in [0.1, 0.01, 0.001, 0.0001]:
    delta_num = numerical.delta_numerical(h)
    delta_ana = comparison['delta']['analytical']
    error = abs(delta_num - delta_ana)
    print(f"  h = {h:.4f}: Delta = {delta_num:.6f}, Error = {error:.2e}")
